const results = [];
try {
  const r = $('Check: WF-301 SEO Content').first().json;
  const last = (r.data||[])[0];
  if (!last) results.push({ name:'WF-301 SEO Content', ok:false, status:'нет запусков' });
  else {
    const ageH = Math.round((Date.now()-new Date(last.stoppedAt||last.startedAt).getTime())/3600000);
    results.push({ name:'WF-301 SEO Content', ok:last.status==='success', status:last.status, age:ageH });
  }
} catch(e) { results.push({ name:'WF-301 SEO Content', ok:false, status:'error' }); }
