// Yandex quota
let yaLine = '';
try {
  const ya = $('Яндекс: квота').first().json;
  const daily = ya.daily_quota || 890;
  const rem = ya.quota_remainder ?? 0;
  const used = daily - rem;
  const pct = Math.round(used/daily*100);
  const bar = '█'.repeat(Math.round(pct/10)) + '░'.repeat(10-Math.round(pct/10));
  yaLine = `\n━━━━━━━━━━━━━━━━━━━━\n🕷 Crawl квоты сегодня:\n  Яндекс:  ${bar} ${used}/${daily} (${pct}%)`;
} catch(e) { yaLine = '\n  Яндекс: ошибка квоты'; }

// Google — show last WF-206 execution
let gLine = '';
try {
  const gEx = $('Check: WF-206 Google Index').first().json;
  const last = (gEx.data||[])[0];
  if (last && last.status === 'success') {
    const ageH = Math.round((Date.now()-new Date(last.stoppedAt).getTime())/3600000);
    gLine = `  Google:  WF-206 ✅ ${ageH}ч назад (100 URL/день лимит)`;
  } else {
    gLine = `  Google:  WF-206 ⏳ ещё не запускался сегодня (05:00 UTC)`;
  }
} catch(e) {}

const errors = results.filter(r => !r.ok);
const ok = results.filter(r => r.ok);

const msk = new Date(Date.now() + 3*3600000);
const t = msk.toLocaleTimeString('ru-RU',{timeZone:'UTC',hour:'2-digit',minute:'2-digit'});

let msg;
if (errors.length === 0) {
  msg = `✅ Все воркфлоу OK (${t} MSK)\n\n` + ok.map(r=>`  ✅ ${r.name} (${r.age}ч назад)`).join('\n');
} else {
  msg = `🚨 АЛЕРТ: ${errors.length} проблем (${t} MSK)\n\n`;
  msg += errors.map(r=>`❌ ${r.name}: ${r.status}${r.age?' ('+r.age+'ч назад)':''}`).join('\n');
  msg += '\n\n✅ Работают:\n' + ok.map(r=>`  ${r.name} (${r.age}ч)`).join('\n');
}
msg += yaLine;
if (gLine) msg += '\n' + gLine;

return [{ json: { text: msg, has_errors: errors.length > 0 } }];
